  ('promotion-1487eb6c-moex-00072', 'promotion-1487eb6c', 'promotion-1487eb6c-moex-110-ac2adf20', 'sub-promotion-1487eb6c-02', NULL, 'single_choice', '甲機關經管之國有房舍於107年間發生火災，火勢迅速延燒鄰近民宅，民宅屋主向甲機關提出國 賠訴訟，截至107年底止，各種證據顯示，甲機關很有可能被判賠償$150,000，但108年底有新 證據顯示，被判賠償之可能性為40%，依中央政府普通公務單位會計制度之一致規定，請問甲機 關108年底應做何種會計分錄？', '["無須作分錄", "借：負債準備 150,000，貸：其他獎補捐助 150,000", "借：負債準備 150,000，貸：業務支出 150,000", "借：負債準備 150,000，貸：資產負債淨額 150,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:32+00:00", "source_pdf_sha1": "58d6a158290d", "answer_pdf_sha1": "241f01d0d5c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "121", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "審計"}'::jsonb, NULL),
  ('promotion-1487eb6c-moex-00073', 'promotion-1487eb6c', 'promotion-1487eb6c-moex-110-ac2adf20', 'sub-promotion-1487eb6c-02', NULL, 'single_choice', '依據甲機關單位決算會計報告顯示，其帳載預付款4,337 元、其他應收款31元、以前年度撥款於 本年度實現數6,734元、繳付公庫數54,844元、收入待納庫數4元、以前年度撥款於本年度繳還之 其他應收款2,478元，退還收入（預收）款80元、公庫撥入數42,470元，請問歲入實現數為何？', '["44,756元", "52,370元", "57,326元", "52,362元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:32+00:00", "source_pdf_sha1": "58d6a158290d", "answer_pdf_sha1": "241f01d0d5c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "121", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "審計"}'::jsonb, NULL),
  ('promotion-1487eb6c-moex-00074', 'promotion-1487eb6c', 'promotion-1487eb6c-moex-110-ac2adf20', 'sub-promotion-1487eb6c-02', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，行政院修正減列支出實現數 500,000 元改列歲出 保留數時，該機關應為之會計分錄為何？', '["借：預付款500,000，貸：經費支出500,000；借：歲出保留數500,000，貸：歲出保留數準 備500,000", "借：其他應收款500,000，貸：經費支出500,000", "借：其他應收款500,000，貸：經費支出500,000；借：歲出保留數500,000，貸：歲出保留數準 備500,000", "借：歲出保留數500,000，貸：歲出保留數準備500,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:32+00:00", "source_pdf_sha1": "58d6a158290d", "answer_pdf_sha1": "241f01d0d5c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "121", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "審計"}'::jsonb, NULL),
  ('promotion-1487eb6c-moex-00075', 'promotion-1487eb6c', 'promotion-1487eb6c-moex-110-ac2adf20', 'sub-promotion-1487eb6c-02', NULL, 'single_choice', '依中央公共債務會計制度之規定，下列關於中央公共債務會計之敘述，何者正確？', '["中央公共債務分內債及外債", "會計業務之處理，依該制度規定辦理，其未規定者，依相關法令規定辦理", "會計年度之開始、終了及結束期間，依會計法規定辦理", "會計制度依會計法第17條規定訂定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:32+00:00", "source_pdf_sha1": "58d6a158290d", "answer_pdf_sha1": "241f01d0d5c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "121", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "審計"}'::jsonb, NULL),
  ('promotion-1487eb6c-moex-00076', 'promotion-1487eb6c', 'promotion-1487eb6c-moex-110-ac2adf20', 'sub-promotion-1487eb6c-02', NULL, 'single_choice', '依政府會計準則公報及中央政府普通公務單位會計制度之一致規定，下列敘述何者正確？', '["中央政府為興辦公共建設所舉借的公債利息，應予以資本化", "甲機關於110年7月21日購入設備並完成運送、安裝、驗收，隨即開始使用。甲機關於7月 30日始支付其應負擔之運費2萬元，支付時應借：業務支出2萬元，貸：公庫撥入數2萬元", "乙機關配合政策，於110年7月3日參與P公司現金增資，以1億元取得該公司增資後30%股 權。同年8月15日乙機關獲配P公司現金股利1.67億元時，應借：繳付公庫數1.67億元，貸： 採權益法之投資評價調整1.67億元", "丙機關經管礦場已開採10年，110年7月31日宣布發現新礦脈且具開採價值，同年1月至7 月已支付之探勘費用，無須轉列遞耗資產"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:32+00:00", "source_pdf_sha1": "58d6a158290d", "answer_pdf_sha1": "241f01d0d5c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "121", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "審計"}'::jsonb, NULL),
